// Express/Next.js API design
// GET    /api/users          → list users
// POST   /api/users          → create user
// GET    /api/users/:id       → get user
// PATCH  /api/users/:id       → update user
// DELETE /api/users/:id       → delete user
// GET    /api/users/:id/posts → user's posts

// Standard response envelope
interface ApiResponse<T> {
  data: T;
  meta?: { page: number; perPage: number; total: number };
  error?: { code: string; message: string; details?: unknown };
}

// Success: { data: { id: '1', name: 'Jo' } }
// List:    { data: [...], meta: { page: 1, perPage: 20, total: 100 } }
// Error:   { error: { code: 'VALIDATION', message: 'Email required', details: { field: 'email' } } }

import jwt from 'jsonwebtoken';

const ACCESS_SECRET = process.env.JWT_ACCESS_SECRET!;
const REFRESH_SECRET = process.env.JWT_REFRESH_SECRET!;

function generateTokens(userId: string) {
  const accessToken = jwt.sign({ sub: userId }, ACCESS_SECRET, { expiresIn: '15m' });
  const refreshToken = jwt.sign({ sub: userId, version: 1 }, REFRESH_SECRET, { expiresIn: '7d' });
  return { accessToken, refreshToken };
}

// Middleware
function authenticate(req: Request) {
  const header = req.headers.get('authorization');
  if (!header?.startsWith('Bearer ')) throw new UnauthorizedError();
  try {
    const payload = jwt.verify(header.slice(7), ACCESS_SECRET);
    return payload as { sub: string };
  } catch {
    throw new UnauthorizedError('Token expired or invalid');
  }
}

// Refresh endpoint
async function refreshToken(req: Request) {
  const token = getCookie(req, 'refresh_token');
  const payload = jwt.verify(token, REFRESH_SECRET) as { sub: string };
  const tokens = generateTokens(payload.sub);
  // Set new refresh token as httpOnly cookie
  return { accessToken: tokens.accessToken };
}

// Offset pagination
async function listUsers(page = 1, perPage = 20) {
  const offset = (page - 1) * perPage;
  const [users, [{ count }]] = await Promise.all([
    db.select().from(usersTable).limit(perPage).offset(offset).orderBy(desc(usersTable.createdAt)),
    db.select({ count: sql<number>`count(*)` }).from(usersTable),
  ]);
  return { data: users, meta: { page, perPage, total: count, pages: Math.ceil(count / perPage) } };
}

// Cursor pagination (preferred for large datasets)
async function listPosts(cursor?: string, limit = 20) {
  let query = db.select().from(postsTable).orderBy(desc(postsTable.id)).limit(limit + 1);
  if (cursor) {
    query = query.where(lt(postsTable.id, cursor));
  }
  const results = await query;
  const hasMore = results.length > limit;
  const data = hasMore ? results.slice(0, -1) : results;
  return {
    data,
    meta: { nextCursor: hasMore ? data[data.length - 1].id : null, hasMore },
  };
}

// In-memory rate limiter (use Redis for production)
const rateLimits = new Map<string, { count: number; resetAt: number }>();

function rateLimit(key: string, maxRequests = 60, windowMs = 60_000): boolean {
  const now = Date.now();
  const entry = rateLimits.get(key);

  if (!entry || now > entry.resetAt) {
    rateLimits.set(key, { count: 1, resetAt: now + windowMs });
    return true;
  }

  if (entry.count >= maxRequests) return false;
  entry.count++;
  return true;
}

// Middleware
function rateLimitMiddleware(req: NextRequest) {
  const ip = req.headers.get('x-forwarded-for') ?? 'unknown';
  if (!rateLimit(ip)) {
    return NextResponse.json(
      { error: { code: 'RATE_LIMITED', message: 'Too many requests' } },
      { status: 429, headers: { 'Retry-After': '60' } }
    );
  }
}

// Error classes
class ApiError extends Error {
  constructor(public statusCode: number, public code: string, message: string, public details?: unknown) {
    super(message);
  }
}
class BadRequest extends ApiError { constructor(msg: string, details?: unknown) { super(400, 'BAD_REQUEST', msg, details); } }
class Unauthorized extends ApiError { constructor(msg = 'Unauthorized') { super(401, 'UNAUTHORIZED', msg); } }
class NotFound extends ApiError { constructor(resource: string) { super(404, 'NOT_FOUND', `${resource} not found`); } }

// Global handler
function handleApiError(error: unknown): NextResponse {
  const requestId = crypto.randomUUID();

  if (error instanceof ApiError) {
    return NextResponse.json({
      error: { code: error.code, message: error.message, details: error.details, requestId }
    }, { status: error.statusCode });
  }

  // Unexpected error — log full details, return generic message
  console.error(`[${requestId}]`, error);
  return NextResponse.json({
    error: { code: 'INTERNAL_ERROR', message: 'An unexpected error occurred', requestId }
  }, { status: 500 });
}
